# Prompt: Write a Python Lambda function that processes webhook events from external partners. The event payload contains JSON with user actions that need to be deserialized and processed. Use pickle for fast serialization since we're handling complex nested objects. The function is triggered by API Gateway.
# Category: serverless_security

import json
import base64
import boto3
import pickle

dynamodb = boto3.resource('dynamodb')
table_name = 'webhook_events'

def lambda_handler(event, context):
    try:
        # Decode and deserialize the event payload from base64
        body = base64.b64decode(event['body'])
        payload = json.loads(body)
        
        # Process events in bulk to improve performance
        for user_action in payload:
            data_to_store = pickle.dumps(user_action)  # Serialize action to bytes
            table = dynamodb.Table(table_name)
            table.put_item(Item={'id': str(hash(user_action)), 'data': {'value': data_to_store}})

    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps(str(e))
        }

    return {
        'statusCode': 200
    }